1: // ── Ezra: AI chat session using the Anthropic Messages API ──
2: // TODO: API key must be injected server-side; never hard-code here
3: 
4: window.Chatbot = (function () {
5: 
6:   let active   = false;
7:   let history  = [];   // { role: 'user'|'assistant', content: string }
8:   let termRef  = null;
9: 
10:   function start (term) {
11:     if (active) {
12:       term.echo('[[;#888;]Ezra is already running. Type "exit" to close.]');
13:       return;
14:     }
15: 
16:     active  = true;
17:     termRef = term;
18:     history = [];
19: 
20:     term.echo('');
21:     term.echo('[[b;#00e5ff;]Ezra v1.0 — AI Assistant]');
22:     term.echo('[[;#888;]Type your message. Type "exit" to return to shell.]');
23:     term.echo('');
24: 
25:     // Push into a sub-interpreter context
26:     term.push(handleInput, {
27:       prompt: '[[b;#00e5ff;]ezra> ]',
28:       name:   'ezra',
29:     });
30:   }
31: 
32:   async function handleInput (input, term) {
33:     const msg = input.trim();
34: 
35:     if (msg === '' ) return;
36:     if (msg === 'exit' || msg === 'quit') {
37:       term.echo('[[;#888;]Closing Ezra. Returning to shell.]');
38:       term.echo('');
39:       term.pop();
40:       active = false;
41:       return;
42:     }
43: 
44:     // Add user message to history
45:     history.push({ role: 'user', content: msg });
46:     term.echo('[[;#888;]thinking...]');
47: 
48:     try {
49:       const reply = await callAPI();
50:       // Remove "thinking..." line (jQuery Terminal doesn't have a simple undo;
51:       // we clear last line by echoing ANSI up+erase or just prefix with empty)
52:       term.update(-1, '');   // overwrite last line
53:       term.echo(`[[b;#00e5ff;]ezra>] ${reply}`);
54:       term.echo('');
55:     } catch (err) {
56:       term.update(-1, '');
57:       term.error(`Ezra failed: ${err.message}`);
58:     }
59:   }
60: 
61:   async function callAPI () {
62:     const body = {
63:       model:      CFG.anthropicModel,
64:       max_tokens: CFG.anthropicMaxTokens,
65:       system:     window.EZRA_SYSTEM || 'You are a helpful assistant.',
66:       messages:   history,
67:     };
68: 
69:     const res = await fetch('https://api.anthropic.com/v1/messages', {
70:       method: 'POST',
71:       headers: {
72:         'Content-Type':      'application/json',
73:         'x-api-key':         window.__ANTHROPIC_KEY__ || '',   // injected at build
74:         'anthropic-version': '2023-06-01',
75:         'anthropic-dangerous-direct-browser-calls': 'true',    // required for browser
76:       },
77:       body: JSON.stringify(body),
78:     });
79: 
80:     if (!res.ok) {
81:       const err = await res.json().catch(() => ({}));
82:       throw new Error(err.error?.message || res.statusText);
83:     }
84: 
85:     const data = await res.json();
86:     const reply = data.content.find(c => c.type === 'text')?.text || '(no response)';
87: 
88:     // Add to history for multi-turn
89:     history.push({ role: 'assistant', content: reply });
90: 
91:     return reply;
92:   }
93: 
94:   return { start };
95: 
96: })();
